import{_ as i,c as e,o as l,a1 as t}from"./chunks/framework.DILC4Csi.js";const p=JSON.parse('{"title":"高度な機能：マルチアカウント管理 | Antigravity Auth","description":"Antigravity Auth プラグインの高度な機能を習得。マルチアカウントの負荷分散、インテリジェントなアカウント選択、レート制限処理、セッション回復、リクエスト変換などの主要な仕組みを深く学びます。","frontmatter":{"title":"高度な機能：マルチアカウント管理 | Antigravity Auth","sidebarTitle":"マルチアカウント管理","subtitle":"高度な機能：マルチアカウント管理","description":"Antigravity Auth プラグインの高度な機能を習得。マルチアカウントの負荷分散、インテリジェントなアカウント選択、レート制限処理、セッション回復、リクエスト変換などの主要な仕組みを深く学びます。","order":3},"headers":[],"relativePath":"ja/NoeFabris/opencode-antigravity-auth/advanced/index.md","filePath":"ja/NoeFabris/opencode-antigravity-auth/advanced/index.md"}'),r={name:"ja/NoeFabris/opencode-antigravity-auth/advanced/index.md"};function o(n,a,h,s,u,d){return l(),e("div",null,[...a[0]||(a[0]=[t('<h1 id="高度な機能" tabindex="-1">高度な機能 <a class="header-anchor" href="#高度な機能" aria-label="Permalink to &quot;高度な機能&quot;">​</a></h1><p>本セクションでは、Antigravity Auth プラグインの高度な機能を深く理解する手助けをします。マルチアカウントの負荷分散、インテリジェントなアカウント選択、レート制限処理、セッション回復、リクエスト変換などの主要な仕組みを網羅しています。クォーターの利用率を最適化する場合でも、複雑な問題をトラブルシューティングする場合でも、必要な回答がここにあります。</p><h2 id="前提条件" tabindex="-1">前提条件 <a class="header-anchor" href="#前提条件" aria-label="Permalink to &quot;前提条件&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">開始前に確認</p><ul><li>✅ <a href="./../start/quick-install/">クイックインストール</a> を完了し、最初のアカウントを正常に追加済み</li><li>✅ <a href="./../start/first-auth-login/">初回認証</a> を完了し、OAuth フローを理解済み</li><li>✅ <a href="./../start/first-request/">初回リクエスト</a> を完了し、プラグインが正常に動作していることを確認済み</li></ul></div><h2 id="学習パス" tabindex="-1">学習パス <a class="header-anchor" href="#学習パス" aria-label="Permalink to &quot;学習パス&quot;">​</a></h2><h3 id="_1-マルチアカウント設定" tabindex="-1">1. <a href="./multi-account-setup/">マルチアカウント設定</a> <a class="header-anchor" href="#_1-マルチアカウント設定" aria-label="Permalink to &quot;1. [マルチアカウント設定](./multi-account-setup/)&quot;">​</a></h3><p>複数の Google アカウントを設定し、クォーターのプーリングと負荷分散を実現します。</p><ul><li>複数のアカウントを追加して、全体的なクォーター上限を引き上げる</li><li>デュアルクォーターシステム（Antigravity + Gemini CLI）を理解する</li><li>シナリオに応じた適切なアカウント数を選択する</li></ul><h3 id="_2-アカウント選択戦略" tabindex="-1">2. <a href="./account-selection-strategies/">アカウント選択戦略</a> <a class="header-anchor" href="#_2-アカウント選択戦略" aria-label="Permalink to &quot;2. [アカウント選択戦略](./account-selection-strategies/)&quot;">​</a></h3><p>sticky、round-robin、hybrid の 3 種類のアカウント選択戦略のベストプラクティスを習得します。</p><ul><li>1 アカウント → sticky 戦略でプロンプトキャッシュを保持</li><li>2-3 アカウント → hybrid 戦略でリクエストをインテリジェントに分散</li><li>4+ アカウント → round-robin 戦略でスループットを最大化</li></ul><h3 id="_3-レート制限処理" tabindex="-1">3. <a href="./rate-limit-handling/">レート制限処理</a> <a class="header-anchor" href="#_3-レート制限処理" aria-label="Permalink to &quot;3. [レート制限処理](./rate-limit-handling/)&quot;">​</a></h3><p>レート制限の検出、自動リトライ、アカウント切り替えの仕組みを理解します。</p><ul><li>5 種類の異なる 429 エラーを区別する</li><li>自動リトライの指数バックオフアルゴリズムを理解する</li><li>マルチアカウントシーンでの自動切り替えロジックを習得する</li></ul><h3 id="_4-セッション回復" tabindex="-1">4. <a href="./session-recovery/">セッション回復</a> <a class="header-anchor" href="#_4-セッション回復" aria-label="Permalink to &quot;4. [セッション回復](./session-recovery/)&quot;">​</a></h3><p>セッション回復の仕組みを理解し、ツール呼び出しの失敗と中断を自動的に処理します。</p><ul><li>tool_result_missing エラーを自動処理</li><li>thinking_block_order の問題を修正</li><li>auto_resume と session_recovery オプションを設定</li></ul><h3 id="_5-リクエスト変換仕組み" tabindex="-1">5. <a href="./request-transformation/">リクエスト変換仕組み</a> <a class="header-anchor" href="#_5-リクエスト変換仕組み" aria-label="Permalink to &quot;5. [リクエスト変換仕組み](./request-transformation/)&quot;">​</a></h3><p>リクエスト変換の仕組みを深く理解し、異なる AI モデルのプロトコル差異に対応する方法を学びます。</p><ul><li>Claude と Gemini モデルのプロトコル差異を理解する</li><li>Schema 非互換による 400 エラーをトラブルシューティング</li><li>最適なパフォーマンスを得るための Thinking 設定を最適化</li></ul><h3 id="_6-設定ガイド" tabindex="-1">6. <a href="./configuration-guide/">設定ガイド</a> <a class="header-anchor" href="#_6-設定ガイド" aria-label="Permalink to &quot;6. [設定ガイド](./configuration-guide/)&quot;">​</a></h3><p>すべての設定オプションを習得し、ニーズに応じてプラグインの動作をカスタマイズします。</p><ul><li>設定ファイルの場所と優先順位</li><li>モデル動作、アカウントローテーション、アプリケーション動作の設定</li><li>シングルアカウント/マルチアカウント/パラレルエージェントシーンの推奨設定</li></ul><h3 id="_7-パラレルエージェント最適化" tabindex="-1">7. <a href="./parallel-agents/">パラレルエージェント最適化</a> <a class="header-anchor" href="#_7-パラレルエージェント最適化" aria-label="Permalink to &quot;7. [パラレルエージェント最適化](./parallel-agents/)&quot;">​</a></h3><p>パラレルエージェントシーンでのアカウント割り当てを最適化し、PID オフセットを有効にします。</p><ul><li>パラレルエージェントシーンでのアカウント競合問題を理解する</li><li>PID オフセットを有効にして、異なるプロセスが異なるアカウントを優先的に選択するようにする</li><li>round-robin 戦略と組み合わせて、マルチアカウントの利用率を最大化</li></ul><h3 id="_8-デバッグログ" tabindex="-1">8. <a href="./debug-logging/">デバッグログ</a> <a class="header-anchor" href="#_8-デバッグログ" aria-label="Permalink to &quot;8. [デバッグログ](./debug-logging/)&quot;">​</a></h3><p>デバッグログを有効にして、問題のトラブルシューティングと実行状態の監視を行います。</p><ul><li>デバッグログを有効にして詳細情報を記録する</li><li>異なるログレベルと適用シーンを理解する</li><li>ログ内容を解釈して問題を迅速に特定する</li></ul><h2 id="次のステップ" tabindex="-1">次のステップ <a class="header-anchor" href="#次のステップ" aria-label="Permalink to &quot;次のステップ&quot;">​</a></h2><p>高度な機能の学習を完了した後、以下が可能になります：</p><ul><li>📖 <a href="./../faq/">よくある質問</a> を参照して、使用中の問題を解決</li><li>📚 <a href="./../appendix/">付録</a> を読んで、アーキテクチャ設計と完全な設定リファレンスを理解</li><li>🔄 <a href="./../changelog/">更新ログ</a> をチェックして、最新の機能と変更を把握</li></ul>',32)])])}const _=i(r,[["render",o]]);export{p as __pageData,_ as default};
